package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bv.BvTools;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBbKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;
import be.schaubroeck.lpb.tools.enumtypes.VrbrwWrkwBv;
import lombok.extern.slf4j.Slf4j;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;

@Slf4j
public class BerekenRuwBelastbaar extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext mainContext) {
        PersoonsDataManager persoonsDataManager = mainContext.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        LoonElementManager manager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        PersoonsFiscaliteit persoonsFiscaliteit = persoonsDataManager.getPersoonsFiscaliteitOpStartFiscaalJaar();
        VrbrwWrkwBv fiscaleWerkwijze = null;
        if (persoonsFiscaliteit != null) {
            fiscaleWerkwijze = persoonsFiscaliteit.getWerkwijzeVrijwilligeBrandweer();
        }
        Persoon persoonKwartaalSimpel = persoonsDataManager.getPersoonKwartaalSimpel();
        if (RekenTools.heeftOpdrachtBedrijfsvoorheffingVrijwilligeBrandweer(persoonKwartaalSimpel)) {
            if (fiscaleWerkwijze != VrbrwWrkwBv.BAREMA_GFV && fiscaleWerkwijze != VrbrwWrkwBv.PERCENTAGE_GFV) {
                Collection<LoonElement> loonElementen = RekenTools.filter(manager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
                RekenTools.replaceKey(loonElementen, RekenBbKey.BELASTBAAR_KEY, RekenBbKey.RUW_BELASTBAAR_KEY);
            } else {
                Collection<LoonElement> loonElementen = RekenTools.filter(manager.getPersoonsElementen(), BvTools.BV_VRIJWILLIGE_BRANDWEER_CHECKER);
                RekenTools.copyValues(loonElementen, RekenBbKey.BELASTBAAR_KEY, RekenBbKey.RUW_BELASTBAAR_KEY);
                log.trace("loonElementen VrBrw:{}", loonElementen);
            }

        }
        return CONTINUE_PROCESSING;
    }

}
